using System.Text.RegularExpressions;

namespace Parsely.Core.Configuration;

public static class ClassificationProbeConfigValidator
{
    // Matches a {n}, {n,}, or {n,m} quantifier shape. Used to detect the malformed
    // variant that contains internal whitespace (e.g. "{8, 12}"), which .NET silently
    // parses as a literal rather than a quantifier — so it compiles fine but never
    // matches as intended.
    private static readonly Regex QuantifierShape = new(
        @"\{\s*\d+\s*(,\s*\d*\s*)?\}",
        RegexOptions.CultureInvariant);

    public static IReadOnlyList<string> ValidateRawJson(string? rawJson) =>
        ValidateRawJson(rawJson, knownDocumentClassIds: null);

    public static IReadOnlyList<string> ValidateRawJson(
        string? rawJson,
        IReadOnlySet<Guid>? knownDocumentClassIds)
    {
        if (string.IsNullOrWhiteSpace(rawJson))
        {
            return [];
        }

        var config = ClassificationProbeConfig.TryParse(rawJson);
        if (config is null)
        {
            return ["classificationProbeConfigJson is not valid JSON"];
        }

        return Validate(config, knownDocumentClassIds);
    }

    public static IReadOnlyList<string> Validate(ClassificationProbeConfig config) =>
        Validate(config, knownDocumentClassIds: null);

    /// <summary>
