    {
        foreach (Match match in QuantifierShape.Matches(pattern))
        {
            // An escaped brace ("\{...") is an intentional literal, not a quantifier — skip it.
            if (match.Index > 0 && pattern[match.Index - 1] == '\\')
            {
                continue;
            }

            if (match.Value.Any(char.IsWhiteSpace))
            {
                return true;
            }
        }

        return false;
    }
